def dfs(r, c):
    if not (0<=r<rows and 0<=c<cols) or grid[r][c] != 1: return 0
    grid[r][c] = 0  # sink
    return 1 + dfs(r+1,c) + dfs(r-1,c) + dfs(r,c+1) + dfs(r,c-1)
best = 0
for r in range(rows):
    for c in range(cols):
        best = max(best, dfs(r,c))
return best
# Time: O(m·n)  Space: O(m·n)
